using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;

CI MAXN=7e3+5,MAXM=6e5+5,MAXA=1e6+5,dx[4]={-1,0},dy[4]={0,-1};
int n,p[MAXN][MAXN],m,s,fa[MAXM],e,si[MAXM];
struct edge
{
    int w,x,y;
    bool operator < (const edge &a) const
	{
		return w<a.w;
	} 
};
vector<edge> a;
bool check(int x,int y)
{
    return (x>0&&x<=n&&y>0&&y<=n);
}
void init()
{
	FOR(i,1,n*n)
	{
		fa[i]=i;
		si[i]=1;
	}
}
int find(int x)
{
    if(fa[x]!=x) fa[x]=find(fa[x]);
    return fa[x];
}
signed main(void)
{
    n=read();
    init();
    FOR(i,1,n)
    {
        FOR(j,1,n)
        {
            p[i][j]=read();
        }
    }
    FOR(i,1,n)
    {
        FOR(j,1,n)
        {
            FOR(k,0,1)
            {
                int nx=i+dx[k],ny=j+dy[k];
                if(check(nx,ny))
                {
                    ++s;
                    edge tmp;
                    tmp.w=abs(p[nx][ny]-p[i][j]);
                    tmp.x=(i-1)*n+j;
                    tmp.y=(nx-1)*n+ny;
                    a.pb(tmp);
                }
            }
        }
    }
    sort(a.begin(),a.end());
    FOR(i,1,s)
    {
        int fx=find(a[i].x),fy=find(a[i].y);
        if(fx!=fy)
        {
            fa[fx]=fy;
            si[fy]+=si[fx];

            if(si[fy]>=(n*n+1)/2)
            {
                write(a[i].w);
                exit(false);
            }
        }
    }
    return false;
}
